/**
 * ScrollToTop Component: Resets scroll position on route change
 */
const ScrollToTop = () => {
  const { pathname } = useLocation();
  useEffect(() => {
    window.scrollTo(0, 0);
  }, [pathname]);
  return null;
};

/**
 * Image Shim: Mimics Next.js Image component API for the current React environment.
 */
const Image = ({ src, alt, width, height, className, priority, style }: {
  src: string;
  alt: string;
  width?: number | string;
  height?: number | string;
  className?: string;
  priority?: boolean;
  style?: React.CSSProperties;
}) => (
  <img
    src={src}
    alt={alt}
    width={width}
    height={height}
    className={className}
    style={style}
    loading={priority ? "eager" : "lazy"}
  />
);

const Header = () => {
  const location = useLocation();
  const bgRef = useRef<HTMLDivElement>(null);
  const isHome = location.pathname === '/';
  // True when the nav sits over the light (white) scroll-sequence area and
  // the nav background itself is still mostly transparent → use dark text.
  const [darkText, setDarkText] = useState(false);

  // On the home page, fade the nav background in as the user scrolls past the
  // scroll-sequence section (#scroll-sequence-section). Off-home: always opaque.
  useEffect(() => {
    const bg = bgRef.current;
    if (!bg) return;

    if (!isHome) {
      bg.style.opacity = '1';
      setDarkText(false);
      return;
    }

    const update = () => {
      const seqSection = document.getElementById('scroll-sequence-section');
      const headingSection = document.getElementById('parallax-heading');
      if (!seqSection) {
        bg.style.opacity = '0';
        setDarkText(false);
        return;
      }
      const seqRect = seqSection.getBoundingClientRect();
      const vh = window.innerHeight;
      // rect.bottom travels from ~vh (section bottom entering from below) to 0
      // (section fully scrolled past). Fade 0 → 1 as it approaches 0.
      const t = Math.max(0, Math.min(1, 1 - seqRect.bottom / vh));
      bg.style.opacity = String(t);

      // Dark text when the bottom edge of the navbar touches a white section.
      // Navbar height is ~72px; trigger when section top scrolls above that line.
      const navH = 72;
      const overSeq = seqRect.top <= navH && seqRect.bottom > 0;
      const headingRect = headingSection?.getBoundingClientRect();
      const overHeading = headingRect
        ? headingRect.top <= navH && headingRect.bottom > 0
        : false;
      const overLightArea = overSeq || overHeading;
      const next = overLightArea && t < 0.5;
      setDarkText(prev => (prev !== next ? next : prev));
    };

    update();
    window.addEventListener('scroll', update, { passive: true });
    window.addEventListener('resize', update);
    return () => {
      window.removeEventListener('scroll', update);
      window.removeEventListener('resize', update);
    };
  }, [isHome]);

  const navLinks = [
    { name: 'About', href: '/about' },
    { name: 'Careers', href: '/careers' },
    { name: 'Blog', href: '/blog' },
    { name: 'Contact', href: '/contact' },
  ];

  return (
    <header className="fixed top-0 left-0 right-0 z-50 group/header">
      {/* Background layer — opacity driven by scroll on the home page */}
      <div
        ref={bgRef}
        aria-hidden
        className="absolute inset-0 bg-primary/95 backdrop-blur-md border-b border-primary-light"
        style={{ opacity: isHome ? 0 : 1 }}
      />
      <nav className="relative container mx-auto px-6 py-3 flex items-center justify-between">
        <Link to="/" className="flex items-center space-x-3 group/brand">
          <PhitopolisLogo
            className="h-12 w-auto"
            color={darkText ? '#0A2A66' : '#FFFFFF'}
            accentColor="#FFC72C"
          />
          <span className={`text-2xl font-display font-bold tracking-tight transition-colors duration-300 uppercase ${darkText ? 'text-primary' : 'text-white'}`}>
            PH<span className="transition-colors duration-500 group-hover/header:text-accent">IT</span>OPOLIS
          </span>
        </Link>

        <div className="hidden md:flex items-center space-x-8">
          {navLinks.map((link) => (
            <Link
              key={link.name}
              to={link.href}
              className={`relative text-sm font-medium transition-colors duration-300 hover:text-accent pb-1 ${
                location.pathname === link.href
                  ? 'text-accent'
                  : darkText
                    ? 'text-primary'
                    : 'text-slate-100'
              }`}
            >
              {link.name}
              {location.pathname === link.href && (
                <motion.div
                  layoutId="navbar-indicator"
                  className="absolute bottom-0 left-0 right-0 h-0.5 bg-accent rounded-full"
                  transition={{ type: "spring", bounce: 0.2, duration: 0.6 }}
                />
              )}
            </Link>
          ))}
        </div>
      </nav>
    </header>
  );
};

